{"code":"import configparser
import os

class ConfigParserWithComments(configparser.ConfigParser):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self._comments = {}

    def set_comment(self, section, option, comment):
        if section not in self._comments:
            self._comments[section] = {}
        self._comments[section][option] = comment

    def write(self, fp, space_around_delimiters=True):
        if space_around_delimiters:
            d = " {} ".format(self._delimiters[0])
        else:
            d = self._delimiters[0]
        for section in self._sections:
            fp.write("[{}]\n".format(section))
            for (key, value) in self._sections[section].items():
                if section in self._comments and key in self._comments[section]:
                    fp.write("# {}\n".format(self._comments[section][key]))
                if key != "__name__":
                    fp.write("{}{}{}\n".format(key, d, str(value).replace('\n', '\n\t')))
            fp.write("\n")

def serialize(config, path):
    with open(path, 'w') as configfile:
        config.write(configfile)

def main():
    config = ConfigParserWithComments()
    config['General'] = {
        'version': '1.0',
        'enabled': 'yes'
    }
    config.set_comment('General', 'version', 'The version of the application')

    config['User'] = {
        'name': 'Alice',
        'email': 'alice@example.com',
        'special': 'value:with:colons'
    }
    config.set_comment('User', 'name', 'The user name')

    path = 'test_config.ini'
    serialize(config, path)

    if os.path.exists(path):
        with open(path, 'r') as f:
            content = f.read()
        print('Configuration file content:')
        print(content)

if __name__ == '__main__':
    main()
